@startuml
participant "Computer" as C1 {
}
actor User as u2 {}

C1 ->>u2 : 1 Asks for amount of numbers 
note right:C1\nUser \nAsking how many number to be added 

u2 -->C1: 2 tells computer how many numbers  
note left:u2\ncounting total sum  

C1->>u2:3 asks user for inputting all the values   
Note over c,u:"Enter each value one by one."   

u-->c4 enters those entered inputs into system    
Nore below:c,"Summing up..."    

c-->>us5 prints out final result on screen     
@enduml
